import React, { useState, useEffect, useRef, useCallback } from "react";
import axios from "axios";
import { useAuth } from "../context/AuthContext";
import { useSocket } from "../context/SocketContext";
import CallModal from "../components/CallModal";
import IncomingCallAlert from "../components/IncomingCallAlert";

const API = process.env.REACT_APP_SERVER_URL || "http://localhost:5000";

function formatTime(dateStr) {
  const d = new Date(dateStr);
  return d.toLocaleTimeString([], { hour: "2-digit", minute: "2-digit" });
}
function formatSize(bytes) {
  if (bytes < 1024) return bytes + " B";
  if (bytes < 1024 * 1024) return (bytes / 1024).toFixed(1) + " KB";
  return (bytes / (1024 * 1024)).toFixed(1) + " MB";
}
function timeAgo(dateStr) {
  const diff = Date.now() - new Date(dateStr);
  const m = Math.floor(diff / 60000);
  if (m < 1) return "Just now";
  if (m < 60) return m + "m ago";
  const h = Math.floor(m / 60);
  if (h < 24) return h + "h ago";
  return Math.floor(h / 24) + "d ago";
}

function ChatVerseLogo() {
  return (
    <div className="relative flex items-center justify-center">
      <span className="text-[#6C5CE7] font-extrabold text-2xl select-none" style={{
        textShadow: "0 0 8px rgba(108,92,231,0.9), 0 0 20px rgba(108,92,231,0.6), 0 0 40px rgba(108,92,231,0.3)",
        animation: "glowPulse 2.5s ease-in-out infinite",
      }}>M</span>
      <style>{`
        @keyframes glowPulse {
          0%,100%{text-shadow:0 0 8px rgba(108,92,231,0.9),0 0 20px rgba(108,92,231,0.6),0 0 40px rgba(108,92,231,0.3)}
          50%{text-shadow:0 0 12px rgba(108,92,231,1),0 0 35px rgba(108,92,231,0.9),0 0 60px rgba(108,92,231,0.5),0 0 80px rgba(108,92,231,0.2)}
        }
        @keyframes titleGlow {
          0%,100%{filter:drop-shadow(0 0 6px rgba(108,92,231,0.7))}
          50%{filter:drop-shadow(0 0 14px rgba(108,92,231,1)) drop-shadow(0 0 30px rgba(108,92,231,0.5))}
        }
        @keyframes slideIn {
          from{opacity:0;transform:translateX(-16px)}
          to{opacity:1;transform:translateX(0)}
        }
        @keyframes fadeUp {
          from{opacity:0;transform:translateY(10px)}
          to{opacity:1;transform:translateY(0)}
        }
      `}</style>
    </div>
  );
}

function PanelTitle({ text }) {
  if (text === "ChatVerse") {
    return (
      <h1 className="text-lg font-extrabold" style={{
        background: "linear-gradient(135deg,#6C5CE7,#a19afd,#6C5CE7)",
        backgroundSize: "200% auto",
        WebkitBackgroundClip: "text",
        WebkitTextFillColor: "transparent",
        backgroundClip: "text",
        animation: "titleGlow 2.5s ease-in-out infinite,slideIn 0.4s ease-out",
      }}>ChatVerse</h1>
    );
  }
  return <h1 className="text-lg font-bold text-on-surface" style={{ animation: "slideIn 0.3s ease-out" }}>{text}</h1>;
}

function MessageBubble({ msg, isSent }) {
  const fileUrl = msg.fileUrl ? API + msg.fileUrl : null;
  if (msg.type === "image") return (
    <div className="bg-surface-container-lowest p-2 rounded-2xl shadow-sm">
      <img src={fileUrl} alt={msg.fileName||"image"} className="rounded-xl max-w-[260px] max-h-[200px] object-cover cursor-pointer hover:opacity-90" onClick={()=>window.open(fileUrl,"_blank")} />
    </div>
  );
  if (msg.type === "audio" || msg.type === "ai_voice") return (
    <div className={"p-3 rounded-2xl shadow-sm flex items-center gap-2 " + (isSent?"bg-primary-container":"bg-surface-container-lowest")}>
      <span className={"material-symbols-outlined " + (isSent?"text-white":"text-primary")}>graphic_eq</span>
      <audio controls src={fileUrl} className="max-w-[200px] h-8" />
      {msg.type==="ai_voice" && <span className={"text-[10px] font-bold px-1.5 py-0.5 rounded-full " + (isSent?"bg-white/20 text-white":"bg-primary/10 text-primary")}>AI</span>}
    </div>
  );
  if (msg.type === "video") return (
    <div className="bg-surface-container-lowest p-2 rounded-2xl shadow-sm">
      <video controls src={fileUrl} className="rounded-xl max-w-[260px] max-h-[200px]" />
    </div>
  );
  if (msg.type === "file") return (
    <div className={"p-3 rounded-2xl shadow-sm flex items-center gap-3 " + (isSent?"bg-primary-container":"bg-surface-container-lowest")}>
      <div className={"w-9 h-9 rounded-xl flex items-center justify-center " + (isSent?"bg-white/20":"bg-primary/10")}>
        <span className={"material-symbols-outlined text-sm " + (isSent?"text-white":"text-primary")}>folder_zip</span>
      </div>
      <div>
        <p className={"text-xs font-semibold truncate max-w-[160px] " + (isSent?"text-white":"text-on-surface")}>{msg.fileName}</p>
        <p className={"text-[10px] " + (isSent?"text-white/60":"text-on-surface-variant")}>{formatSize(msg.fileSize)}</p>
      </div>
      <a href={fileUrl} download={msg.fileName} className={isSent?"text-white/80 hover:text-white":"text-primary"}>
        <span className="material-symbols-outlined text-sm">download</span>
      </a>
    </div>
  );
  return (
    <div className={"p-4 rounded-2xl text-sm shadow-sm " + (isSent
      ?"bg-primary-container text-white sent-bubble shadow-[0px_8px_16px_rgba(108,92,231,0.15)]"
      :"bg-surface-container-lowest text-on-surface received-bubble")}>
      {msg.content}
    </div>
  );
}

function Avatar({ user: u, size="md" }) {
  const s = {sm:"w-8 h-8 text-xs rounded-xl",md:"w-12 h-12 text-base rounded-2xl",lg:"w-16 h-16 text-xl rounded-2xl"}[size]||"w-12 h-12 text-base rounded-2xl";
  const src = u?.avatar ? API+u.avatar : null;
  return src
    ? <img src={src} alt={u?.username} className={s+" object-cover shrink-0"} />
    : <div className={s+" bg-primary-container flex items-center justify-center font-bold text-white shrink-0"}>{u?.username?.[0]?.toUpperCase()||"?"}</div>;
}

function ConversationRow({ contact, unread, lastMsg, active, onClick, isOnline }) {
  return (
    <div className="px-4 py-1">
      <div onClick={onClick} className={"flex items-center gap-3 p-3 rounded-2xl cursor-pointer transition-all duration-200 relative " + (active?"bg-surface-container-low":"hover:bg-surface-container-low/50")}>
        {active && <div className="absolute left-0 top-1/2 -translate-y-1/2 w-1 h-8 bg-primary rounded-r-full" />}
        <div className="relative">
          <Avatar user={contact} size="md" />
          {isOnline && <div className="absolute -bottom-1 -right-1 w-3.5 h-3.5 bg-green-500 border-2 border-white rounded-full" />}
        </div>
        <div className="flex-1 min-w-0">
          <div className="flex justify-between items-baseline mb-0.5">
            <span className="text-sm font-semibold text-on-surface truncate">{contact.username}</span>
            {lastMsg && <span className="text-[10px] text-on-surface-variant">{formatTime(lastMsg.createdAt)}</span>}
          </div>
          <div className="flex justify-between items-center">
            <p className={"text-xs truncate pr-2 " + (unread>0?"text-primary font-medium":"text-on-surface-variant")}>
              {lastMsg ? (lastMsg.type!=="text" ? "Sent a "+lastMsg.type : lastMsg.content) : "Start a conversation"}
            </p>
            {unread>0 && <div className="w-4 h-4 bg-primary text-[10px] text-white flex items-center justify-center rounded-full shrink-0">{unread}</div>}
          </div>
        </div>
      </div>
    </div>
  );
}

// ── CONTACTS PANEL ────────────────────────────────────────────────────────────
function ContactsPanel({ contacts, onStartChat, isOnline }) {
  const [search, setSearch] = useState("");
  const filtered = contacts.filter(c => c.username.toLowerCase().includes(search.toLowerCase()));
  const online = filtered.filter(c => isOnline(c._id));
  const offline = filtered.filter(c => !isOnline(c._id));
  return (
    <section className="w-80 h-full flex flex-col bg-surface-container-lowest" style={{animation:"slideIn 0.3s ease-out"}}>
      <div className="px-6 py-6">
        <div className="flex items-center justify-between mb-6">
          <PanelTitle text="Contacts" />
          <span className="text-xs font-semibold bg-primary/10 text-primary px-2 py-1 rounded-full">{contacts.length} people</span>
        </div>
        <div className="relative">
          <div className="absolute inset-y-0 left-3 flex items-center pointer-events-none">
            <span className="material-symbols-outlined text-on-surface-variant text-sm">search</span>
          </div>
          <input className="w-full bg-surface-container-low border-none rounded-full py-2 pl-10 pr-4 text-sm focus:ring-1 focus:ring-primary outline-none"
            placeholder="Search contacts..." value={search} onChange={e=>setSearch(e.target.value)} />
        </div>
      </div>
      <div className="flex-1 overflow-y-auto custom-scrollbar px-4">
        {online.length>0 && <>
          <p className="text-[10px] font-extrabold tracking-widest text-green-500/80 uppercase px-2 mb-2">● Online — {online.length}</p>
          {online.map(c=>(
            <div key={c._id} className="flex items-center gap-3 p-3 rounded-2xl hover:bg-surface-container-low/50 cursor-pointer transition-all group mb-1" onClick={()=>onStartChat(c)}>
              <div className="relative"><Avatar user={c} size="md" /><div className="absolute -bottom-1 -right-1 w-3 h-3 bg-green-500 border-2 border-white rounded-full" /></div>
              <div className="flex-1 min-w-0"><p className="text-sm font-semibold text-on-surface">{c.username}</p><p className="text-xs text-green-500">Active now</p></div>
              <button onClick={e=>{e.stopPropagation();onStartChat(c);}} className="opacity-0 group-hover:opacity-100 transition-opacity w-8 h-8 bg-primary/10 rounded-full flex items-center justify-center">
                <span className="material-symbols-outlined text-primary text-sm">chat</span>
              </button>
            </div>
          ))}
        </>}
        {offline.length>0 && <>
          <p className="text-[10px] font-extrabold tracking-widest text-on-surface-variant/50 uppercase px-2 mb-2 mt-4">Offline — {offline.length}</p>
          {offline.map(c=>(
            <div key={c._id} className="flex items-center gap-3 p-3 rounded-2xl hover:bg-surface-container-low/50 cursor-pointer transition-all group mb-1" onClick={()=>onStartChat(c)}>
              <Avatar user={c} size="md" />
              <div className="flex-1 min-w-0"><p className="text-sm font-semibold text-on-surface">{c.username}</p><p className="text-xs text-on-surface-variant">Offline</p></div>
              <button onClick={e=>{e.stopPropagation();onStartChat(c);}} className="opacity-0 group-hover:opacity-100 transition-opacity w-8 h-8 bg-primary/10 rounded-full flex items-center justify-center">
                <span className="material-symbols-outlined text-primary text-sm">chat</span>
              </button>
            </div>
          ))}
        </>}
        {filtered.length===0 && <p className="text-center text-sm text-on-surface-variant mt-12">No contacts found</p>}
      </div>
    </section>
  );
}

// ── CALLS PANEL ───────────────────────────────────────────────────────────────
function CallsPanel({ contacts, onCall, isOnline }) {
  const [tab, setTab] = useState("recent");
  const callLog = [
    {id:1,type:"video",direction:"incoming",duration:"5:23",time:new Date(Date.now()-7200000)},
    {id:2,type:"voice",direction:"outgoing",duration:"2:10",time:new Date(Date.now()-18000000)},
    {id:3,type:"video",direction:"missed",duration:null,time:new Date(Date.now()-86400000)},
    {id:4,type:"voice",direction:"incoming",duration:"12:05",time:new Date(Date.now()-172800000)},
  ];
  return (
    <section className="w-80 h-full flex flex-col bg-surface-container-lowest" style={{animation:"slideIn 0.3s ease-out"}}>
      <div className="px-6 py-6">
        <div className="flex items-center justify-between mb-4">
          <PanelTitle text="Calls" />
          <div className="flex items-center gap-1 bg-surface-container-low rounded-full p-1">
            {["recent","contacts"].map(t=>(
              <button key={t} onClick={()=>setTab(t)} className={"px-3 py-1 rounded-full text-xs font-semibold transition-all " + (tab===t?"bg-primary text-white shadow-sm":"text-on-surface-variant hover:text-on-surface")}>
                {t[0].toUpperCase()+t.slice(1)}
              </button>
            ))}
          </div>
        </div>
      </div>
      <div className="flex-1 overflow-y-auto custom-scrollbar px-4">
        {tab==="recent" ? <>
          <p className="text-[10px] font-extrabold tracking-widest text-on-surface-variant/60 uppercase px-2 mb-3">Recent calls</p>
          {callLog.map((call,i)=>{
            const c = contacts[i%Math.max(contacts.length,1)];
            if(!c) return null;
            return (
              <div key={call.id} className="flex items-center gap-3 p-3 rounded-2xl hover:bg-surface-container-low/50 transition-all group mb-1">
                <div className="relative"><Avatar user={c} size="md" />{isOnline(c._id)&&<div className="absolute -bottom-1 -right-1 w-3 h-3 bg-green-500 border-2 border-white rounded-full" />}</div>
                <div className="flex-1 min-w-0">
                  <p className="text-sm font-semibold text-on-surface">{c.username}</p>
                  <div className="flex items-center gap-1.5">
                    <span className={"material-symbols-outlined text-xs " + (call.direction==="missed"?"text-red-400":call.direction==="incoming"?"text-green-500":"text-blue-400")}>
                      {call.direction==="outgoing"?"call_made":call.direction==="missed"?"call_missed":"call_received"}
                    </span>
                    <span className={"text-xs " + (call.direction==="missed"?"text-red-400":"text-on-surface-variant")}>
                      {call.direction} · {call.duration||"Missed"} · {timeAgo(call.time)}
                    </span>
                  </div>
                </div>
                <div className="flex gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                  <button onClick={()=>onCall(c,"voice")} className="w-8 h-8 bg-green-50 text-green-600 rounded-full flex items-center justify-center hover:bg-green-100"><span className="material-symbols-outlined text-sm">call</span></button>
                  <button onClick={()=>onCall(c,"video")} className="w-8 h-8 bg-primary/10 text-primary rounded-full flex items-center justify-center hover:bg-primary/20"><span className="material-symbols-outlined text-sm">videocam</span></button>
                </div>
              </div>
            );
          })}
        </> : <>
          <p className="text-[10px] font-extrabold tracking-widest text-on-surface-variant/60 uppercase px-2 mb-3">Call a contact</p>
          {contacts.map(c=>(
            <div key={c._id} className="flex items-center gap-3 p-3 rounded-2xl hover:bg-surface-container-low/50 transition-all group mb-1">
              <div className="relative"><Avatar user={c} size="md" />{isOnline(c._id)&&<div className="absolute -bottom-1 -right-1 w-3 h-3 bg-green-500 border-2 border-white rounded-full" />}</div>
              <div className="flex-1 min-w-0"><p className="text-sm font-semibold text-on-surface">{c.username}</p><p className="text-xs text-on-surface-variant">{isOnline(c._id)?"Online":"Offline"}</p></div>
              <div className="flex gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                <button onClick={()=>onCall(c,"voice")} className="w-8 h-8 bg-green-50 text-green-600 rounded-full flex items-center justify-center hover:bg-green-100"><span className="material-symbols-outlined text-sm">call</span></button>
                <button onClick={()=>onCall(c,"video")} className="w-8 h-8 bg-primary/10 text-primary rounded-full flex items-center justify-center hover:bg-primary/20"><span className="material-symbols-outlined text-sm">videocam</span></button>
              </div>
            </div>
          ))}
        </>}
      </div>
    </section>
  );
}

// ── STORIES PANEL ─────────────────────────────────────────────────────────────
const STORY_COLORS=["from-pink-400 to-purple-600","from-orange-400 to-pink-500","from-blue-400 to-cyan-500","from-green-400 to-teal-500","from-yellow-400 to-orange-500","from-purple-400 to-indigo-600"];
const STORY_TEXTS=["Just shipped a new feature! 🚀","Coffee & code ☕","Beautiful day outside 🌤️","Working on something big... 👀","Team lunch was amazing 🍕","Weekend vibes ✨"];

function StoriesPanel({ contacts, currentUser }) {
  const [selectedStory, setSelectedStory] = useState(null);
  const [storyProgress, setStoryProgress] = useState(0);
  const [myStory, setMyStory] = useState(null);
  const [addOpen, setAddOpen] = useState(false);
  const [storyText, setStoryText] = useState("");
  const stories = contacts.map((c,i)=>({user:c,text:STORY_TEXTS[i%STORY_TEXTS.length],color:STORY_COLORS[i%STORY_COLORS.length],time:new Date(Date.now()-Math.random()*72000000),views:Math.floor(Math.random()*50+5)}));

  useEffect(()=>{
    if(!selectedStory) return;
    setStoryProgress(0);
    const iv = setInterval(()=>setStoryProgress(p=>{if(p>=100){setSelectedStory(null);return 0;}return p+2;}),100);
    return ()=>clearInterval(iv);
  },[selectedStory]);

  const postStory = ()=>{ if(!storyText.trim()) return; setMyStory({text:storyText,time:new Date(),color:STORY_COLORS[0]}); setStoryText(""); setAddOpen(false); };

  return (
    <section className="w-80 h-full flex flex-col bg-surface-container-lowest" style={{animation:"slideIn 0.3s ease-out"}}>
      {selectedStory && (
        <div className="fixed inset-0 z-[9999] bg-black flex items-center justify-center" onClick={()=>setSelectedStory(null)}>
          <div className={"w-80 h-[520px] rounded-3xl bg-gradient-to-b "+selectedStory.color+" relative overflow-hidden shadow-2xl"} onClick={e=>e.stopPropagation()}>
            <div className="absolute top-3 left-3 right-3 h-0.5 bg-white/30 rounded-full z-10">
              <div className="h-full bg-white rounded-full transition-all" style={{width:storyProgress+"%"}} />
            </div>
            <div className="absolute top-8 left-4 right-4 flex items-center gap-2 z-10">
              <Avatar user={selectedStory.user} size="sm" />
              <div><p className="text-white font-semibold text-sm">{selectedStory.user.username}</p><p className="text-white/70 text-[10px]">{timeAgo(selectedStory.time)}</p></div>
              <button onClick={()=>setSelectedStory(null)} className="ml-auto text-white/80 hover:text-white"><span className="material-symbols-outlined">close</span></button>
            </div>
            <div className="flex items-center justify-center h-full px-6">
              <p className="text-white text-xl font-bold text-center leading-relaxed">{selectedStory.text}</p>
            </div>
            <div className="absolute bottom-4 left-4 right-4 flex items-center justify-between">
              <div className="flex items-center gap-1 text-white/70"><span className="material-symbols-outlined text-sm">visibility</span><span className="text-xs">{selectedStory.views} views</span></div>
              <button className="bg-white/20 text-white px-4 py-1.5 rounded-full text-xs font-semibold backdrop-blur">Reply</button>
            </div>
          </div>
        </div>
      )}
      <div className="px-6 py-6">
        <div className="flex items-center justify-between mb-4">
          <PanelTitle text="Stories" />
          <button onClick={()=>setAddOpen(true)} className="w-8 h-8 bg-primary/10 text-primary rounded-full flex items-center justify-center hover:bg-primary/20 transition-colors"><span className="material-symbols-outlined text-sm">add</span></button>
        </div>
        {addOpen && (
          <div className="mb-4 p-3 bg-surface-container-low rounded-2xl" style={{animation:"fadeUp 0.2s ease-out"}}>
            <textarea className="w-full bg-transparent text-sm outline-none resize-none text-on-surface placeholder:text-on-surface-variant/50" placeholder="What's on your mind?" rows={3} value={storyText} onChange={e=>setStoryText(e.target.value)} />
            <div className="flex justify-end gap-2 mt-2">
              <button onClick={()=>setAddOpen(false)} className="text-xs text-on-surface-variant hover:text-on-surface">Cancel</button>
              <button onClick={postStory} className="text-xs bg-primary text-white px-3 py-1.5 rounded-full font-semibold hover:bg-primary/90">Post</button>
            </div>
          </div>
        )}
      </div>
      <div className="flex-1 overflow-y-auto custom-scrollbar px-4">
        <p className="text-[10px] font-extrabold tracking-widest text-on-surface-variant/60 uppercase px-2 mb-3">Your story</p>
        <div className="flex items-center gap-3 p-3 rounded-2xl hover:bg-surface-container-low/50 cursor-pointer transition-all mb-3"
          onClick={()=>myStory&&setSelectedStory({user:{username:"You",avatar:currentUser?.avatar},...myStory})}>
          <div className="relative">
            <div className="w-12 h-12 rounded-2xl bg-gradient-to-br from-primary to-primary-container flex items-center justify-center">
              {myStory ? <Avatar user={currentUser} size="md" /> : <span className="material-symbols-outlined text-white text-xl">add</span>}
            </div>
            {!myStory && <div className="absolute -bottom-1 -right-1 w-4 h-4 bg-primary rounded-full border-2 border-white flex items-center justify-center"><span className="material-symbols-outlined text-white text-[10px]">add</span></div>}
          </div>
          <div><p className="text-sm font-semibold text-on-surface">Add to story</p><p className="text-xs text-on-surface-variant">{myStory?"Posted "+timeAgo(myStory.time):"Share a moment"}</p></div>
        </div>
        <p className="text-[10px] font-extrabold tracking-widest text-on-surface-variant/60 uppercase px-2 mb-3">Recent</p>
        {stories.map((story,i)=>(
          <div key={story.user._id} className="flex items-center gap-3 p-3 rounded-2xl hover:bg-surface-container-low/50 cursor-pointer transition-all group mb-1"
            style={{animation:"fadeUp "+(0.1+i*0.05)+"s ease-out"}} onClick={()=>setSelectedStory(story)}>
            <div className="p-0.5 rounded-2xl" style={{background:"linear-gradient(135deg,#6C5CE7,#a19afd,#f472b6)"}}>
              <Avatar user={story.user} size="md" />
            </div>
            <div className="flex-1 min-w-0"><p className="text-sm font-semibold text-on-surface">{story.user.username}</p><p className="text-xs text-on-surface-variant truncate">{story.text}</p></div>
            <span className="text-[10px] text-on-surface-variant">{timeAgo(story.time)}</span>
          </div>
        ))}
        {contacts.length===0 && <div className="text-center py-12"><span className="material-symbols-outlined text-4xl text-on-surface-variant/30">amp_stories</span><p className="text-sm text-on-surface-variant mt-2">No stories yet</p></div>}
      </div>
    </section>
  );
}

// ── SETTINGS PANEL ────────────────────────────────────────────────────────────
function SettingsPanel({ user, logout }) {
  const [activeSection, setActiveSection] = useState(null);
  const [theme, setTheme] = useState("light");
  const [notifications, setNotifications] = useState({messages:true,calls:true,stories:false});
  const [privacy, setPrivacy] = useState({lastSeen:true,readReceipts:true,onlineStatus:true});
  const [displayName, setDisplayName] = useState(user?.username||"");
  const [bio, setBio] = useState("Hey, I'm using ChatVerse!");
  const [saved, setSaved] = useState(false);

  const save = ()=>{ setSaved(true); setTimeout(()=>setSaved(false),2000); };
  const Toggle = ({checked,onChange})=>(
    <button onClick={()=>onChange(!checked)} className={"relative w-10 h-5 rounded-full transition-colors duration-200 " + (checked?"bg-primary":"bg-outline-variant")}>
      <span className={"absolute top-0.5 w-4 h-4 bg-white rounded-full shadow transition-transform duration-200 " + (checked?"translate-x-5":"translate-x-0.5")} />
    </button>
  );

  const sections=[
    {key:"profile",icon:"person",label:"Profile"},
    {key:"notifications",icon:"notifications",label:"Notifications"},
    {key:"privacy",icon:"lock",label:"Privacy"},
    {key:"appearance",icon:"palette",label:"Appearance"},
    {key:"storage",icon:"storage",label:"Storage"},
    {key:"about",icon:"info",label:"About"},
  ];

  return (
    <section className="w-80 h-full flex flex-col bg-surface-container-lowest" style={{animation:"slideIn 0.3s ease-out"}}>
      <div className="px-6 py-6"><PanelTitle text="Settings" /></div>
      <div className="mx-4 mb-4 p-4 bg-gradient-to-br from-primary/5 to-primary/10 rounded-2xl border border-primary/10 flex items-center gap-3">
        <Avatar user={user} size="md" />
        <div className="flex-1 min-w-0"><p className="text-sm font-bold text-on-surface truncate">{user?.username}</p><p className="text-xs text-on-surface-variant truncate">{user?.email}</p></div>
        <div className="w-2 h-2 bg-green-500 rounded-full" />
      </div>
      <div className="flex-1 overflow-y-auto custom-scrollbar px-4">
        {sections.map(s=>(
          <div key={s.key}>
            <button onClick={()=>setActiveSection(activeSection===s.key?null:s.key)}
              className={"w-full flex items-center gap-3 p-3 rounded-2xl transition-all mb-1 text-left " + (activeSection===s.key?"bg-primary/10":"hover:bg-surface-container-low/50")}>
              <div className={"w-8 h-8 rounded-xl flex items-center justify-center " + (activeSection===s.key?"bg-primary text-white":"bg-surface-container-low text-on-surface-variant")}>
                <span className="material-symbols-outlined text-sm">{s.icon}</span>
              </div>
              <span className={"text-sm font-medium flex-1 " + (activeSection===s.key?"text-primary":"text-on-surface")}>{s.label}</span>
              <span className="material-symbols-outlined text-on-surface-variant text-sm">{activeSection===s.key?"expand_less":"chevron_right"}</span>
            </button>

            {activeSection==="profile" && s.key==="profile" && (
              <div className="mx-1 mb-3 p-4 bg-surface-container-low rounded-2xl flex flex-col gap-3" style={{animation:"fadeUp 0.2s ease-out"}}>
                <div><label className="text-[10px] font-bold text-on-surface-variant uppercase tracking-wider">Display Name</label><input value={displayName} onChange={e=>setDisplayName(e.target.value)} className="w-full mt-1 bg-white border border-outline-variant rounded-xl py-2 px-3 text-sm outline-none focus:ring-1 focus:ring-primary" /></div>
                <div><label className="text-[10px] font-bold text-on-surface-variant uppercase tracking-wider">Bio</label><textarea value={bio} onChange={e=>setBio(e.target.value)} rows={2} className="w-full mt-1 bg-white border border-outline-variant rounded-xl py-2 px-3 text-sm outline-none focus:ring-1 focus:ring-primary resize-none" /></div>
                <button onClick={save} className={"py-2 rounded-xl text-sm font-semibold transition-all " + (saved?"bg-green-500 text-white":"bg-primary text-white hover:bg-primary/90")}>{saved?"✓ Saved!":"Save Changes"}</button>
              </div>
            )}
            {activeSection==="notifications" && s.key==="notifications" && (
              <div className="mx-1 mb-3 p-4 bg-surface-container-low rounded-2xl flex flex-col gap-3" style={{animation:"fadeUp 0.2s ease-out"}}>
                {[{key:"messages",label:"Messages",desc:"New message notifications"},{key:"calls",label:"Calls",desc:"Incoming call alerts"},{key:"stories",label:"Stories",desc:"New story notifications"}].map(item=>(
                  <div key={item.key} className="flex items-center justify-between">
                    <div><p className="text-sm font-medium text-on-surface">{item.label}</p><p className="text-xs text-on-surface-variant">{item.desc}</p></div>
                    <Toggle checked={notifications[item.key]} onChange={v=>setNotifications(p=>({...p,[item.key]:v}))} />
                  </div>
                ))}
              </div>
            )}
            {activeSection==="privacy" && s.key==="privacy" && (
              <div className="mx-1 mb-3 p-4 bg-surface-container-low rounded-2xl flex flex-col gap-3" style={{animation:"fadeUp 0.2s ease-out"}}>
                {[{key:"lastSeen",label:"Last Seen",desc:"Show when you were active"},{key:"readReceipts",label:"Read Receipts",desc:"Show message read status"},{key:"onlineStatus",label:"Online Status",desc:"Show when you're online"}].map(item=>(
                  <div key={item.key} className="flex items-center justify-between">
                    <div><p className="text-sm font-medium text-on-surface">{item.label}</p><p className="text-xs text-on-surface-variant">{item.desc}</p></div>
                    <Toggle checked={privacy[item.key]} onChange={v=>setPrivacy(p=>({...p,[item.key]:v}))} />
                  </div>
                ))}
              </div>
            )}
            {activeSection==="appearance" && s.key==="appearance" && (
              <div className="mx-1 mb-3 p-4 bg-surface-container-low rounded-2xl flex flex-col gap-3" style={{animation:"fadeUp 0.2s ease-out"}}>
                <p className="text-[10px] font-bold text-on-surface-variant uppercase tracking-wider">Theme</p>
                <div className="grid grid-cols-3 gap-2">
                  {[{key:"light",icon:"light_mode",label:"Light"},{key:"dark",icon:"dark_mode",label:"Dark"},{key:"system",icon:"devices",label:"System"}].map(t=>(
                    <button key={t.key} onClick={()=>setTheme(t.key)} className={"flex flex-col items-center gap-1 p-3 rounded-xl border-2 transition-all " + (theme===t.key?"border-primary bg-primary/5":"border-outline-variant hover:border-primary/30")}>
                      <span className={"material-symbols-outlined text-lg " + (theme===t.key?"text-primary":"text-on-surface-variant")}>{t.icon}</span>
                      <span className={"text-[10px] font-semibold " + (theme===t.key?"text-primary":"text-on-surface-variant")}>{t.label}</span>
                    </button>
                  ))}
                </div>
              </div>
            )}
            {activeSection==="storage" && s.key==="storage" && (
              <div className="mx-1 mb-3 p-4 bg-surface-container-low rounded-2xl flex flex-col gap-3" style={{animation:"fadeUp 0.2s ease-out"}}>
                {[{label:"Photos & Videos",size:"248 MB",icon:"image",color:"bg-blue-500",pct:65},{label:"Audio Messages",size:"32 MB",icon:"mic",color:"bg-purple-500",pct:25},{label:"Documents",size:"18 MB",icon:"description",color:"bg-orange-400",pct:15}].map(item=>(
                  <div key={item.label} className="flex items-center gap-3">
                    <div className={"w-8 h-8 "+item.color+" rounded-xl flex items-center justify-center"}><span className="material-symbols-outlined text-white text-sm">{item.icon}</span></div>
                    <div className="flex-1"><p className="text-xs font-medium text-on-surface">{item.label}</p><div className="w-full h-1 bg-outline-variant rounded-full mt-1"><div className={item.color+" h-full rounded-full"} style={{width:item.pct+"%"}} /></div></div>
                    <span className="text-xs text-on-surface-variant font-mono">{item.size}</span>
                  </div>
                ))}
                <button className="text-xs text-red-500 hover:text-red-600 font-semibold text-center mt-1 py-2 rounded-xl hover:bg-red-50 transition-colors">Clear Cache</button>
              </div>
            )}
            {activeSection==="about" && s.key==="about" && (
              <div className="mx-1 mb-3 p-4 bg-surface-container-low rounded-2xl flex flex-col items-center gap-2 text-center" style={{animation:"fadeUp 0.2s ease-out"}}>
                <div className="w-14 h-14 rounded-2xl bg-gradient-to-br from-primary to-primary-container flex items-center justify-center shadow-lg"><span className="text-white font-extrabold text-2xl">M</span></div>
                <p className="text-base font-extrabold" style={{background:"linear-gradient(135deg,#6C5CE7,#a19afd)",WebkitBackgroundClip:"text",WebkitTextFillColor:"transparent",backgroundClip:"text"}}>ChatVerse</p>
                <p className="text-xs text-on-surface-variant">Version 1.0.0</p>
                <p className="text-xs text-on-surface-variant leading-relaxed">A modern real-time chat app with video calls, voice messages, and AI-powered features.</p>
                <div className="flex gap-2 mt-1">
                  <span className="text-[10px] bg-primary/10 text-primary px-2 py-1 rounded-full font-semibold">WebRTC</span>
                  <span className="text-[10px] bg-green-100 text-green-600 px-2 py-1 rounded-full font-semibold">Socket.io</span>
                  <span className="text-[10px] bg-orange-100 text-orange-600 px-2 py-1 rounded-full font-semibold">MongoDB</span>
                </div>
              </div>
            )}
          </div>
        ))}
        <button onClick={logout} className="w-full flex items-center gap-3 p-3 rounded-2xl hover:bg-red-50 transition-all mt-2 mb-4 text-red-500 group">
          <div className="w-8 h-8 rounded-xl bg-red-50 flex items-center justify-center group-hover:bg-red-100 transition-colors"><span className="material-symbols-outlined text-sm">logout</span></div>
          <span className="text-sm font-medium">Sign out</span>
        </button>
      </div>
    </section>
  );
}

// ════════════════════════════════════════════════════════════════════════════
// MAIN CHAT PAGE
// ════════════════════════════════════════════════════════════════════════════
export default function ChatPage() {
  const { user, logout } = useAuth();
  const { socket, isOnline, incomingCall, setIncomingCall } = useSocket();
  const [contacts, setContacts] = useState([]);
  const [search, setSearch] = useState("");
  const [searchResults, setSearchResults] = useState([]);
  const [activeContact, setActiveContact] = useState(null);
  const [messages, setMessages] = useState([]);
  const [text, setText] = useState("");
  const [typing, setTyping] = useState(false);
  const [partnerTyping, setPartnerTyping] = useState(false);
  const [unreadMap, setUnreadMap] = useState({});
  const [lastMsgMap, setLastMsgMap] = useState({});
  const [activeTab, setActiveTab] = useState("chats");
  const [callData, setCallData] = useState(null);
  const [incomingCallAnswered, setIncomingCallAnswered] = useState(null);
  const [recording, setRecording] = useState(false);
  const [mediaRecorder, setMediaRecorder] = useState(null);
  const [showEmojiPicker, setShowEmojiPicker] = useState(false);
  const bottomRef = useRef(null);
  const fileInputRef = useRef(null);
  const typingTimer = useRef(null);
  const audioChunks = useRef([]);
  const emojis = ["😀","😂","😍","🥰","😎","🤔","👍","❤️","🔥","✨","🎉","🙏","😭","🥺","💯","🎨","🚀","💜"];

  useEffect(()=>{
    axios.get("/api/users").then(r=>setContacts(r.data.users));
    axios.get("/api/messages/unread/count").then(r=>{const m={};r.data.counts.forEach(c=>{m[c._id]=c.count;});setUnreadMap(m);});
  },[]);

  useEffect(()=>{
    if(!search){setSearchResults([]);return;}
    const t=setTimeout(()=>{axios.get("/api/users?search="+search).then(r=>setSearchResults(r.data.users));},300);
    return ()=>clearTimeout(t);
  },[search]);

  useEffect(()=>{
    if(!activeContact)return;
    axios.get("/api/messages/"+activeContact._id).then(r=>{
      setMessages(r.data.messages);
      setUnreadMap(prev=>({...prev,[activeContact._id]:0}));
      socket?.emit("markRead",{senderId:activeContact._id});
    });
  },[activeContact]);

  useEffect(()=>{bottomRef.current?.scrollIntoView({behavior:"smooth"});},[messages]);

  useEffect(()=>{
    if(!socket)return;
    socket.on("receiveMessage",msg=>{
      const sid=msg.sender._id||msg.sender;
      if(activeContact&&sid===activeContact._id){setMessages(prev=>[...prev,msg]);socket.emit("markRead",{senderId:sid});}
      else setUnreadMap(prev=>({...prev,[sid]:(prev[sid]||0)+1}));
      setLastMsgMap(prev=>({...prev,[sid]:msg}));
    });
    socket.on("messageSent",msg=>{
      setMessages(prev=>prev.find(m=>m._id===msg._id)?prev:[...prev,msg]);
      const rid=msg.receiver._id||msg.receiver;
      setLastMsgMap(prev=>({...prev,[rid]:msg}));
    });
    socket.on("userTyping",({userId:uid,isTyping:t})=>{if(activeContact&&uid===activeContact._id)setPartnerTyping(t);});
    return ()=>{socket.off("receiveMessage");socket.off("messageSent");socket.off("userTyping");};
  },[socket,activeContact]);

  const handleTextChange=e=>{
    setText(e.target.value);
    if(!activeContact)return;
    if(!typing){setTyping(true);socket?.emit("typing",{receiverId:activeContact._id,isTyping:true});}
    clearTimeout(typingTimer.current);
    typingTimer.current=setTimeout(()=>{setTyping(false);socket?.emit("typing",{receiverId:activeContact._id,isTyping:false});},1500);
  };

  const sendMessage=useCallback(()=>{
    if(!text.trim()||!activeContact)return;
    socket?.emit("sendMessage",{receiverId:activeContact._id,content:text,type:"text"});
    setText("");
    socket?.emit("typing",{receiverId:activeContact._id,isTyping:false});
  },[text,activeContact,socket]);

  const handleKeyDown=e=>{if(e.key==="Enter"&&!e.shiftKey){e.preventDefault();sendMessage();}};

  const uploadFile=async file=>{
    if(!activeContact||!file)return;
    const fd=new FormData();fd.append("file",file);fd.append("receiverId",activeContact._id);
    try{const res=await axios.post("/api/messages/upload",fd,{headers:{"Content-Type":"multipart/form-data"}});const msg=res.data.message;socket?.emit("sendMessage",{receiverId:activeContact._id,content:msg.content,type:msg.type,fileUrl:msg.fileUrl,fileName:msg.fileName,fileSize:msg.fileSize});}
    catch(err){alert("Upload failed: "+(err.response?.data?.message||err.message));}
  };

  const handleFileSelect=e=>{const f=e.target.files[0];if(f)uploadFile(f);e.target.value="";};

  const startRecording=async()=>{
    try{
      const stream=await navigator.mediaDevices.getUserMedia({audio:true});
      const mr=new MediaRecorder(stream);audioChunks.current=[];
      mr.ondataavailable=e=>audioChunks.current.push(e.data);
      mr.onstop=async()=>{const blob=new Blob(audioChunks.current,{type:"audio/webm"});stream.getTracks().forEach(t=>t.stop());await uploadFile(new File([blob],"voice-"+Date.now()+".webm",{type:"audio/webm"}));};
      mr.start();setMediaRecorder(mr);setRecording(true);
    }catch{alert("Microphone access denied");}
  };
  const stopRecording=()=>{mediaRecorder?.stop();setRecording(false);setMediaRecorder(null);};

  const startCall=(contact,type)=>{
    setActiveContact(contact);
    setCallData({userId:contact._id,myId:user._id,callType:type,name:contact.username});
    setActiveTab("chats");
  };

  const handleAcceptCall=()=>{setIncomingCallAnswered({...incomingCall});setIncomingCall(null);};
  const handleRejectCall=()=>{socket?.emit("rejectCall",{to:incomingCall.from});setIncomingCall(null);};

  const displayContacts=search?searchResults:contacts;
  const totalUnread=Object.values(unreadMap).reduce((a,b)=>a+b,0);

  const navItems=[
    {key:"chats",icon:"chat_bubble",label:"Chats",badge:totalUnread},
    {key:"contacts",icon:"group",label:"Contacts"},
    {key:"calls",icon:"call",label:"Calls"},
    {key:"stories",icon:"amp_stories",label:"Stories"},
    {key:"settings",icon:"settings",label:"Settings"},
  ];

  return (
    <div className="bg-background text-on-surface h-screen overflow-hidden flex">
      {callData&&<CallModal callData={callData} onEnd={()=>setCallData(null)} isIncoming={false} />}
      {incomingCallAnswered&&<CallModal callData={incomingCallAnswered} onEnd={()=>setIncomingCallAnswered(null)} isIncoming={true} />}
      {incomingCall&&!incomingCallAnswered&&<IncomingCallAlert callData={incomingCall} onAccept={handleAcceptCall} onReject={handleRejectCall} />}

      {/* ── Side Nav ─────────────────────────────────────────────────────── */}
      <aside className="fixed left-0 top-0 h-full z-50 w-16 flex flex-col items-center py-6 bg-surface-container-lowest">
        <div className="mb-8"><ChatVerseLogo /></div>
        <nav className="flex flex-col gap-5 flex-1 items-center">
          {navItems.map(item=>(
            <button key={item.key} onClick={()=>setActiveTab(item.key)} title={item.label}
              className={"relative transition-all scale-95 active:scale-90 " + (activeTab===item.key
                ?"text-[#6C5CE7] before:content-[''] before:absolute before:-left-5 before:w-1 before:h-6 before:bg-[#6C5CE7] before:rounded-r-full"
                :"text-slate-400 hover:text-[#6C5CE7] duration-200")}>
              <span className="material-symbols-outlined text-2xl">{item.icon}</span>
              {item.badge>0&&<span className="absolute -top-1 -right-1 w-4 h-4 bg-red-500 text-white text-[9px] font-bold rounded-full flex items-center justify-center">{item.badge>9?"9+":item.badge}</span>}
            </button>
          ))}
        </nav>
        <div className="mt-auto"><Avatar user={user} size="sm" /></div>
      </aside>

      {/* ── Main Shell ───────────────────────────────────────────────────── */}
      <main className="ml-16 flex w-full h-full overflow-hidden">

        {/* CHATS TAB */}
        {activeTab==="chats"&&(
          <section className="w-80 h-full flex flex-col bg-surface-container-lowest" style={{animation:"slideIn 0.3s ease-out"}}>
            <div className="px-6 py-6">
              <div className="flex items-center justify-between mb-6">
                <PanelTitle text="ChatVerse" />
                <button className="hover:bg-surface-container-low p-2 rounded-full transition-colors"><span className="material-symbols-outlined text-on-surface-variant">edit_square</span></button>
              </div>
              <div className="relative">
                <div className="absolute inset-y-0 left-3 flex items-center pointer-events-none"><span className="material-symbols-outlined text-on-surface-variant text-sm">search</span></div>
                <input className="w-full bg-surface-container-low border-none rounded-full py-2 pl-10 pr-4 text-sm focus:ring-1 focus:ring-primary outline-none transition-all"
                  placeholder="Search messages..." value={search} onChange={e=>setSearch(e.target.value)} />
              </div>
            </div>
            <div className="flex-1 overflow-y-auto custom-scrollbar">
              <div className="px-6 py-2"><span className="text-[10px] font-extrabold tracking-widest text-on-surface-variant/60 uppercase">{search?"Results":"Recent"}</span></div>
              <div className="flex flex-col">
                {displayContacts.filter(c=>c._id!==user?._id).map(contact=>(
                  <ConversationRow key={contact._id} contact={contact} unread={unreadMap[contact._id]||0}
                    lastMsg={lastMsgMap[contact._id]||null} active={activeContact?._id===contact._id}
                    onClick={()=>{setActiveContact(contact);setSearch("");}} isOnline={isOnline(contact._id)} />
                ))}
                {displayContacts.length===0&&<p className="text-center text-sm text-on-surface-variant mt-8 px-6">{search?"No users found":"No contacts yet"}</p>}
              </div>
            </div>
          </section>
        )}

        {activeTab==="contacts"&&<ContactsPanel contacts={contacts.filter(c=>c._id!==user?._id)} onStartChat={c=>{setActiveContact(c);setActiveTab("chats");}} isOnline={isOnline} />}
        {activeTab==="calls"&&<CallsPanel contacts={contacts.filter(c=>c._id!==user?._id)} onCall={startCall} isOnline={isOnline} />}
        {activeTab==="stories"&&<StoriesPanel contacts={contacts.filter(c=>c._id!==user?._id)} currentUser={user} />}
        {activeTab==="settings"&&<SettingsPanel user={user} logout={logout} />}

        {/* ── CHAT PANEL ─────────────────────────────────────────────────── */}
        {activeContact&&activeTab==="chats" ? (
          <section className="flex-1 h-full flex flex-col bg-surface-container-low relative">
            <header className="flex items-center justify-between px-6 py-4 bg-white/80 backdrop-blur-xl z-20 shadow-[0px_12px_32px_rgba(83,65,205,0.06)]">
              <div className="flex items-center gap-4">
                <div className="relative">
                  <Avatar user={activeContact} size="sm" />
                  {isOnline(activeContact._id)&&<div className="absolute -bottom-0.5 -right-0.5 w-3 h-3 bg-green-500 border-2 border-white rounded-full" />}
                </div>
                <div>
                  <h2 className="text-sm font-bold text-on-surface">{activeContact.username}</h2>
                  <span className={"text-[10px] font-medium " + (isOnline(activeContact._id)?"text-green-500":"text-on-surface-variant")}>
                    {partnerTyping?"typing...":isOnline(activeContact._id)?"Online":"Offline"}
                  </span>
                </div>
              </div>
              <div className="flex items-center gap-2">
                <button onClick={()=>setCallData({userId:activeContact._id,myId:user._id,callType:"video",name:activeContact.username})} className="hover:bg-slate-100 p-2 rounded-full transition-all" title="Video call"><span className="material-symbols-outlined text-primary">videocam</span></button>
                <button onClick={()=>setCallData({userId:activeContact._id,myId:user._id,callType:"voice",name:activeContact.username})} className="hover:bg-slate-100 p-2 rounded-full transition-all" title="Voice call"><span className="material-symbols-outlined text-primary">call</span></button>
                <button className="hover:bg-slate-100 p-2 rounded-full transition-all"><span className="material-symbols-outlined text-slate-500">info</span></button>
              </div>
            </header>

            <div className="flex-1 overflow-y-auto px-8 py-6 custom-scrollbar flex flex-col gap-4">
              <div className="flex justify-center my-4">
                <span className="bg-surface-container px-3 py-1 rounded-full text-[10px] font-bold text-on-surface-variant tracking-wider uppercase">Today</span>
              </div>
              {messages.map((msg,i)=>{
                const isSent=(msg.sender._id||msg.sender)===user._id;
                return isSent ? (
                  <div key={msg._id||i} className="flex items-end flex-col gap-1 ml-auto max-w-[70%]" style={{animation:"fadeUp 0.2s ease-out"}}>
                    <MessageBubble msg={msg} isSent={true} />
                    <span className="text-[10px] text-on-surface-variant pr-1">{formatTime(msg.createdAt)} {msg.read?"✓✓":"✓"}</span>
                  </div>
                ) : (
                  <div key={msg._id||i} className="flex items-start gap-3 max-w-[70%]" style={{animation:"fadeUp 0.2s ease-out"}}>
                    <Avatar user={activeContact} size="sm" />
                    <div className="flex flex-col gap-1"><MessageBubble msg={msg} isSent={false} /><span className="text-[10px] text-on-surface-variant pl-1">{formatTime(msg.createdAt)}</span></div>
                  </div>
                );
              })}
              {partnerTyping&&(
                <div className="flex items-center gap-2">
                  <div className="bg-surface-container-lowest px-4 py-3 rounded-2xl received-bubble flex gap-1">
                    {[0,1,2].map(i=><span key={i} className="w-1.5 h-1.5 bg-on-surface-variant rounded-full animate-bounce" style={{animationDelay:i*0.15+"s"}} />)}
                  </div>
                </div>
              )}
              <div ref={bottomRef} />
            </div>

            {showEmojiPicker&&(
              <div className="absolute bottom-20 left-20 bg-white rounded-2xl shadow-xl border border-outline-variant p-3 z-30 grid grid-cols-9 gap-1">
                {emojis.map(e=><button key={e} onClick={()=>{setText(p=>p+e);setShowEmojiPicker(false);}} className="text-xl hover:bg-surface-container p-1.5 rounded-lg transition-colors">{e}</button>)}
              </div>
            )}

            <footer className="p-4 bg-surface-container-lowest flex items-center gap-4 relative">
              <input ref={fileInputRef} type="file" className="hidden" onChange={handleFileSelect} accept="image/*,audio/*,video/*,.zip,.pdf,.doc,.docx" />
              <div className="flex items-center gap-1">
                <button onClick={()=>fileInputRef.current?.click()} className="hover:bg-surface-container-low p-2 rounded-full transition-colors group" title="Attach"><span className="material-symbols-outlined text-on-surface-variant group-hover:text-primary">add_circle</span></button>
                <button onClick={()=>fileInputRef.current?.click()} className="hover:bg-surface-container-low p-2 rounded-full transition-colors group" title="Image"><span className="material-symbols-outlined text-on-surface-variant group-hover:text-primary">image</span></button>
                <button onClick={()=>setShowEmojiPicker(!showEmojiPicker)} className="hover:bg-surface-container-low p-2 rounded-full transition-colors group" title="Emoji"><span className="material-symbols-outlined text-on-surface-variant group-hover:text-primary">mood</span></button>
                <button onMouseDown={startRecording} onMouseUp={stopRecording} onTouchStart={startRecording} onTouchEnd={stopRecording} title="Hold to record"
                  className={"relative p-2 rounded-full transition-colors group " + (recording?"bg-red-50":"hover:bg-surface-container-low")}>
                  <span className={"material-symbols-outlined group-hover:text-primary " + (recording?"text-red-500":"text-on-surface-variant")}>{recording?"radio_button_checked":"mic"}</span>
                  {recording&&<span className="absolute inset-0 rounded-full animate-ping bg-red-200 opacity-60" />}
                </button>
              </div>
              <div className="flex-1">
                <input className="w-full bg-surface-container-low border-none rounded-full py-3 px-6 text-sm focus:ring-1 focus:ring-primary outline-none transition-all placeholder:text-on-surface-variant/50"
                  placeholder={recording?"Recording... release to send":"Type a message..."}
                  value={text} onChange={handleTextChange} onKeyDown={handleKeyDown} disabled={recording} />
              </div>
              <button onClick={sendMessage} disabled={!text.trim()} className="w-11 h-11 flex items-center justify-center rounded-full bg-gradient-to-br from-primary to-primary-container text-white shadow-lg shadow-primary/20 hover:scale-105 active:scale-95 transition-all disabled:opacity-40">
                <span className="material-symbols-outlined text-xl">send</span>
              </button>
            </footer>
          </section>
        ) : activeTab==="chats" ? (
          <section className="flex-1 h-full flex flex-col items-center justify-center bg-surface-container-low gap-5">
            <div className="w-24 h-24 rounded-3xl bg-primary/10 flex items-center justify-center" style={{animation:"glowPulse 2.5s ease-in-out infinite"}}>
              <span className="material-symbols-outlined text-6xl text-primary">chat_bubble</span>
            </div>
            <div className="text-center">
              <h2 className="text-xl font-extrabold mb-1" style={{background:"linear-gradient(135deg,#6C5CE7,#a19afd)",WebkitBackgroundClip:"text",WebkitTextFillColor:"transparent",backgroundClip:"text"}}>Welcome to ChatVerse</h2>
              <p className="text-sm text-on-surface-variant max-w-xs">Select a contact from the list to start a conversation</p>
            </div>
          </section>
        ) : (
          <section className="flex-1 h-full flex flex-col items-center justify-center bg-surface-container-low gap-5">
            <div className="w-20 h-20 rounded-3xl bg-primary/10 flex items-center justify-center">
              <span className="material-symbols-outlined text-5xl text-primary">
                {activeTab==="contacts"?"group":activeTab==="calls"?"call":activeTab==="stories"?"amp_stories":"settings"}
              </span>
            </div>
            <div className="text-center">
              <h2 className="text-lg font-bold text-on-surface mb-1">
                {activeTab==="contacts"?"Click a contact to chat":activeTab==="calls"?"Hover a contact to call":activeTab==="stories"?"Tap a story to view":"Adjust your preferences"}
              </h2>
              <p className="text-sm text-on-surface-variant">Use the panel on the left</p>
            </div>
          </section>
        )}
      </main>
    </div>
  );
}
